data.output:
350	}
351	
352	func randomProgressID() string {
353		return fmt.Sprintf("%x", time.Now().UnixNano())[:8]
354	}
355	
356	func (w *ExecuteBeadWorker) Run(ctx context.Context, rcfg config.ResolvedConfig, runtime ExecuteBeadLoopRuntime) (*ExecuteBeadLoopResult, error) {
357		if w.Store == nil {
358			return nil, fmt.Errorf("execute-bead loop: store is required")
359		}
360		if w.Executor == nil {
361			return nil, fmt.Errorf("execute-bead loop: executor is required")
362		}
363	
364		now := w.Now
365		if now == nil {
366			now = time.Now
367		}
368		assignee := rcfg.Assignee()
369		if assignee == "" {
370			assignee = "ddx"
371		}
372		noProgressCooldown := rcfg.NoProgressCooldown()
373		if noProgressCooldown <= 0 {
374			noProgressCooldown = 6 * time.Hour
375		}
376		maxNoChangesBeforeClose := rcfg.MaxNoChangesBeforeClose()
377		if maxNoChangesBeforeClose <= 0 {
378			maxNoChangesBeforeClose = 3
379		}
380		heartbeatInterval := rcfg.HeartbeatInterval()
381		if heartbeatInterval <= 0 {
382			heartbeatInterval = bead.HeartbeatInterval
383		}
384		harness := rcfg.Harness()
385		model := rcfg.Model()
386		profile := rcfg.Profile()
387	
388		result := &ExecuteBeadLoopResult{}
389		attempted := make(map[string]struct{})
390		// triagedWarned suppresses the one-time boot warning when ComplexityGate is
391		// nil. One warning per Run() invocation is enough; the bool resets on the
392		// next worker boot.
393		triagedWarned := false
394		// hookFailed tracks beads whose pre-claim hook failed on first presentation
395		// in this run. A bead in hookFailed but not attempted gets one retry: on the
396		// second hook failure it moves to attempted so nextCandidate will skip it and
397		// the loop can exit gracefully. This prevents infinite spinning when the hook
398		// always fails while still allowing transient hook failures to be retried.
399		hookFailed := make(map[string]struct{})
400	
401		emit := func(eventType string, data map[string]any) {
402			writeLoopEvent(runtime.EventSink, runtime.SessionID, eventType, data, now().UTC())
403		}
404	
405		emit("loop.start", map[string]any{
406			"worker_id":    runtime.WorkerID,
407			"project_root": runtime.ProjectRoot,
408			"harness":      harness,
409			"model":        model,
410			"session_id":   runtime.SessionID,
411			"assignee":     assignee,
412			"once":         runtime.Once,
413		})
414		// exitReason is populated as the loop exits to surface a structured reason
415		// in the loop.end event (ddx-dc157075 AC #4). Recognized values: "sigterm",
416		// "sigint", "fatal_config", "once_complete", "explicit_poll_zero". The
417		// "providers_exhausted" slot is reserved for ddx-aede917d (quota pause).
418		exitReason := ""
419		defer func() {
420			emit("loop.end", map[string]any{
421				"attempts":            result.Attempts,
422				"successes":           result.Successes,
423				"failures":            result.Failures,
424				"last_failure_status": result.LastFailureStatus,
425				"exit_reason":         exitReason,
426			})
427		}()
428	
429		for {
430			// Respect context cancellation between iterations. Without this check,
431			// a Stop() request (which cancels ctx) would only take effect during
432			// the idle poll sleep — the loop would happily claim the next ready
433			// bead as soon as the current Execute returned, ignoring the cancel.
434			if err := ctx.Err(); err != nil {
435				if exitReason == "" {
436					switch err {
437					case context.Canceled:
438						exitReason = "sigint"
439					case context.DeadlineExceeded:
440						exitReason = "sigterm"
441					default:
442						exitReason = "context_cancelled"
443					}
444				}
445				return result, err
446			}
447	
448			candidate, skips, ok, err := w.nextCandidate(attempted, runtime.LabelFilter)
449			if err != nil {
450				exitReason = "fatal_config"
451				return result, err
452			}
453			// Diagnostic: when nextCandidate selected a lower-priority bead while
454			// at least one higher-priority bead was skipped, emit a structured
455			// picker.priority_skip event naming each skipped bead and the reason
456			// (ddx-9d55601f AC #4). Without this surface, an operator who sees a
457			// worker claim a P2 while P0s sit in `ddx bead ready` cannot tell
458			// whether the picker has a bug, the P0s are filtered upstream, or a
459			// label filter is in play.
460			if ok {
461				emitPickerPrioritySkips(emit, candidate, skips)
462			}
463			if !ok {
464				if result.Attempts == 0 {
465					result.NoReadyWork = true
466					if diag, ok := w.Store.(readyDiagnoser); ok {
467						if breakdown, bErr := diag.ReadyExecutionBreakdown(); bErr == nil {
468							result.NoReadyWorkDetail = NoReadyWorkBreakdown{
469								SkippedEpics:       breakdown.SkippedEpics,
470								SkippedOnCooldown:  breakdown.SkippedOnCooldown,
471								SkippedNotEligible: breakdown.SkippedNotEligible,
472								SkippedSuperseded:  breakdown.SkippedSuperseded,
473								NextRetryAfter:     breakdown.NextRetryAfter,
474							}
475						}
476					}
477				}
478				if runtime.PollInterval <= 0 {
479					// Legacy "drain-and-exit" semantics: operator either passed
480					// --once (handled at end-of-iteration) or explicitly set
481					// --poll-interval=0. ddx-dc157075: with default --poll-interval
482					// flipped to 30s in CLI/server, this path now only fires for
483					// the explicit opt-out case.
484					if runtime.Once {
485						exitReason = "once_complete"
486					} else {
487						exitReason = "explicit_poll_zero"
488					}
489					return result, nil
490				}
491				// --once with poll-interval > 0: an empty queue still means there
492				// is no work to pick, and --once explicitly asked for at-most-one.
493				// Returning here preserves the operator-visible "drain and stop"
494				// semantics of --once even when the long-running default applies.
495				if runtime.Once {
496					exitReason = "once_complete"
497					return result, nil
498				}
499				// Long-running drain (poll-interval > 0): emit a transient
500				// "no_ready_work" event so server-managed workers can surface this
501				// as an idle substate (ddx-dc157075 AC #5) instead of treating it
502				// as terminal.
503				emit("loop.idle", map[string]any{
504					"reason":        "no_ready_work",
505					"poll_interval": runtime.PollInterval.String(),
506				})
507				// Surface the idle substate via the progress channel so server-side
508				// drainProgress can flip WorkerRecord.Substate to "idle" without
509				// reading the JSONL event log. Phase="loop.idle" is treated as a
510				// substate signal, not a per-bead attempt phase.
511				emitProgress(runtime.ProgressCh, ProgressEvent{
512					EventID:   "evt-" + randomProgressID(),
513					WorkerID:  runtime.WorkerID,
514					ProjectID: runtime.ProjectRoot,
515					Phase:     "loop.idle",
516					Heartbeat: true,
517					TS:        now().UTC(),
518					Message:   "no_ready_work",
519				})
520				// Reset per-Run attempted/hookFailed maps before sleeping
521				// (ddx-dc157075 AC #2). Without this reset, beads attempted earlier
522				// in this Run remain filtered out of nextCandidate forever, so the
523				// "attempted-once = exit" trap reasserts itself: a bead whose
524				// cooldown has expired since its last attempt would never be
525				// re-picked by the same long-running worker.
526				for k := range attempted {
527					delete(attempted, k)
528				}
529				for k := range hookFailed {
530					delete(hookFailed, k)
531				}
532				if err := sleepOrWake(ctx, runtime.PollInterval, runtime.WakeCh); err != nil {
533					if exitReason == "" {
534						switch err {
535						case context.Canceled:
536							exitReason = "sigint"
537						case context.DeadlineExceeded:
538							exitReason = "sigterm"
539						default:
540							exitReason = "context_cancelled"
541						}
542					}
543					return result, err
544				}
545				continue
546			}
547	
548			// Found a candidate: clear any "idle" substate set on the previous
549			// no-candidate iteration (ddx-dc157075 AC #5).

550			emitProgress(runtime.ProgressCh, ProgressEvent{
551				EventID:   "evt-" + randomProgressID(),
552				WorkerID:  runtime.WorkerID,
553				ProjectID: runtime.ProjectRoot,
554				BeadID:    candidate.ID,
555				Phase:     "loop.active",
556				Heartbeat: true,
557				TS:        now().UTC(),
558			})
559	
560			// Pre-claim hook: fetch origin + verify ancestry before claiming.
561			// On error the bead is skipped for this iteration; the loop
562			// continues (ctx is not cancelled). The bead is NOT added to
563			// attempted on the FIRST failure so a transient hook failure (e.g.
564			// diverged branch) allows a retry on the next iteration. On a
565			// SECOND failure for the same bead in the same run it is moved into
566			// attempted so nextCandidate will skip it, preventing an infinite
567			// loop when the hook always fails.
568			if runtime.PreClaimHook != nil {
569				if hookErr := runtime.PreClaimHook(ctx); hookErr != nil {
570					if runtime.Log != nil {
571						_, _ = fmt.Fprintf(runtime.Log, "pre-claim hook: %v (skipping %s)\n", hookErr, candidate.ID)
572					}
573					emit("preclaim.skipped", map[string]any{
574						"bead_id": candidate.ID,
575						"reason":  hookErr.Error(),
576					})
577					if _, alreadyFailed := hookFailed[candidate.ID]; alreadyFailed {
578						// Second failure in this run: stop retrying this bead.
579						attempted[candidate.ID] = struct{}{}
580					} else {
581						hookFailed[candidate.ID] = struct{}{}
582					}
583					continue
584				}
585			}
586	
587			attempted[candidate.ID] = struct{}{}
588	
589			// Routing preflight gate (FEAT-006 D3, ddx-98e6e9ef): consult the
590			// upstream typed-incompatibility surface BEFORE claiming. If the
591			// configured (harness, model) cannot serve the bead, exit the loop
592			// with a worker-level failure record — no claim, no executor
593			// invocation, no tier-attempt event burn.
594			if runtime.RoutePreflight != nil {
595				if rerr := runtime.RoutePreflight(ctx, harness, model); rerr != nil {
596					detail := fmt.Sprintf("routing preflight rejected (harness=%s model=%s): %s",
597						harness, model, rerr.Error())
598					if runtime.Log != nil {
599						_, _ = fmt.Fprintf(runtime.Log, "routing preflight: %s (skipping %s)\n",
600							detail, candidate.ID)
601					}
602					emit("preflight.rejected", map[string]any{
603						"bead_id": candidate.ID,
604						"harness": harness,
605						"model":   model,
606						"reason":  rerr.Error(),
607					})
608					report := ExecuteBeadReport{
609						BeadID:  candidate.ID,
610						Status:  ExecuteBeadStatusExecutionFailed,
611						Detail:  detail,
612						Harness: harness,
613						Model:   model,
614					}
615					result.Attempts++
616					result.Failures++
617					result.LastFailureStatus = report.Status
618					result.Results = append(result.Results, report)
619					// ddx-dc157075 AC #3: do NOT abandon the rest of the queue on
620					// a single bead's preflight rejection. Continue to the next
621					// candidate. If --once was requested we still honour it.
622					if runtime.Once {
623						exitReason = "once_complete"
624						return result, nil
625					}
626					continue
627				}
628			}
629	
630			// Complexity triage gate (ddx-5bf4ee7e): pre-Claim decomposition check.
631			// When the gate is nil, decomposition responsibility shifts to the
632			// LLM-driven path inside execute-bead (ddx-b790449b AC5): the agent
633			// is prompted to recognize coarse beads, file children, and exit
634			// early. The pre-dispatch warning is intentionally suppressed —
635			// it is no longer accurate now that decomposition lives downstream.
636			if w.ComplexityGate == nil {
637				_ = triagedWarned // retained for future re-introduction of a typed gate
638			} else {
639				shouldClaim, triageErr := w.ComplexityGate(ctx, candidate)
640				if triageErr != nil {
641					if runtime.Log != nil {
642						_, _ = fmt.Fprintf(runtime.Log,
643							"triage gate error for %s: %v (skipping)\n", candidate.ID, triageErr)
644					}
645					emit("triage.error", map[string]any{
646						"bead_id": candidate.ID,
647						"reason":  triageErr.Error(),
648					})
649					// A gate error does not count as an attempt; re-pick next candidate.
650					continue
651				}
652				if !shouldClaim {
653					if runtime.Log != nil {
654						_, _ = fmt.Fprintf(runtime.Log,
655							"triage: skipped dispatch of %s (classified as non-atomic)\n", candidate.ID)
656					}
657					emit("triage.skipped", map[string]any{"bead_id": candidate.ID})
658					continue
659				}
660			}
661	
662			if err := w.Store.Claim(candidate.ID, assignee); err != nil {
663				// Another worker won the race for this bead. Emit a structured
664				// claim_race event so concurrent-worker losses are observable
665				// (ddx-9d55601f AC #4). The bead remains in `attempted` for this
666				// run; on the next iteration it will be filtered out of
667				// ReadyExecution naturally because Claim() flipped it to
668				// in_progress, so the loser keeps moving down priority order.
669				emit("picker.claim_race", map[string]any{
670					"bead_id":  candidate.ID,
671					"priority": candidate.Priority,
672					"reason":   err.Error(),
673				})
674				continue
675			}
676	
677			emit("bead.claimed", map[string]any{
678				"bead_id":  candidate.ID,
679				"title":    candidate.Title,
680				"assignee": assignee,
681			})
682	
683			if runtime.Log != nil {
684				if candidate.Title != "" {
685					_, _ = fmt.Fprintf(runtime.Log, "\n▶ %s: %s\n", candidate.ID, candidate.Title)
686				} else {
687					_, _ = fmt.Fprintf(runtime.Log, "\n▶ %s\n", candidate.ID)
688				}
689			}
690	
691			// Generate a provisional attempt_id for progress events.
692			// The real attempt_id is assigned inside ExecuteBead; we use this
693			// for queueing/running events and replace with the real one once known.
694			provAttemptID := time.Now().UTC().Format("20060102T150405") + "-" + randomProgressID()
695			runStart := now()
696			phaseSeq := 0
697			nextPhase := func(phase string, heartbeat bool) {
698				phaseSeq++
699				emitProgress(runtime.ProgressCh, newProgressEvent(
700					runtime.WorkerID, runtime.ProjectRoot, candidate.ID, provAttemptID,
701					harness, model, profile,
702					phase, phaseSeq, heartbeat, now().Sub(runStart).Milliseconds(),
703				))
704			}
705	
706			nextPhase("queueing", false)
707	
708			hbCtx, hbCancel := context.WithCancel(ctx)
709			var hbWG sync.WaitGroup
710			hbWG.Add(1)
711			go func(beadID string) {
712				defer hbWG.Done()
713				ticker := time.NewTicker(heartbeatInterval)
714				defer ticker.Stop()
715				for {
716					select {
717					case <-hbCtx.Done():
718						return
719					case <-ticker.C:
720						_ = w.Store.Heartbeat(beadID)
721					}
722				}
723			}(candidate.ID)
724	
725			nextPhase("running", false)
726	
727			report, err := w.Executor.Execute(ctx, candidate.ID)
728			hbCancel()
729			hbWG.Wait()
730			if err != nil {
731				report = ExecuteBeadReport{
732					BeadID: candidate.ID,
733					Status: ExecuteBeadStatusExecutionFailed,
734					Detail: err.Error(),
735				}
736			}
737			if report.BeadID == "" {
738				report.BeadID = candidate.ID
739			}
740			if report.Status == "" {
741				report.Status = ExecuteBeadStatusExecutionFailed
742			}
743			if report.Detail == "" {
744				report.Detail = ExecuteBeadStatusDetail(report.Status, "", "")
745			}
746	
747			result.Attempts++
748	
749			if report.Status == ExecuteBeadStatusSuccess {
750				appendLoopRoutingEvidence(w.Store, candidate.ID, report, now().UTC())
751				// Story 15: when an operator-prompt bead succeeds, scan
752				// base..result for affected beads and artifacts, and append
753				// origin_operator_prompt_id back-link events. Failure is
754				// logged but does not fail the attempt — the bead's own
755				// commit has already landed and the audit data is best-effort.
756				if candidate.IssueType == bead.IssueTypeOperatorPrompt {
757					affected, affErr := computeOperatorPromptAffected(runtime.ProjectRoot, report.BaseRev, report.ResultRev, candidate.ID)
758					if affErr != nil {
759						if runtime.Log != nil {
760							_, _ = fmt.Fprintf(runtime.Log, "operator-prompt backlinks scan: %v\n", affErr)
761						}
762					} else if recErr := recordOperatorPromptBacklinks(w.Store, candidate.ID, affected, assignee, now().UTC()); recErr != nil {
763						if runtime.Log != nil {
764							_, _ = fmt.Fprintf(runtime.Log, "operator-prompt backlinks: %v\n", recErr)
765						}
766					}
767				}
768				// Close the bead early when review is skipped. The closure gate
769				// (ddx-e30e60a9) accepts this path because closing_commit_sha is
770				// set and there is no malformed-APPROVE event to reject.
771				reviewApproved := true
772				reviewSkipped := w.Reviewer == nil || runtime.NoReview || HasBeadLabel(candidate.Labels, "review:skip")
773	
774				if reviewSkipped {
775					if err := w.Store.CloseWithEvidence(candidate.ID, report.SessionID, report.ResultRev); err != nil {
776						if w.handleOutcomeStoreError(ctx, candidate.ID, "CloseWithEvidence", err, assignee, result, runtime, now) {
777							continue
778						}
779						return result, ctx.Err()
780					}
781				}
782	
783				if w.Reviewer != nil && !runtime.NoReview && !HasBeadLabel(candidate.Labels, "review:skip") {
784					implRouting := ImplementerRouting{
785						Harness:     report.Harness,
786						Provider:    report.Provider,
787						Model:       report.Model,
788						ActualPower: report.ActualPower,
789						Correlation: map[string]string{
790							"bead_id":    candidate.ID,
791							"attempt_id": report.AttemptID,
792							"session_id": report.SessionID,
793							"result_rev": report.ResultRev,
794						},
795					}
796					reviewRes, reviewErr := w.Reviewer.ReviewBead(ctx, candidate.ID, report.ResultRev, implRouting)
797					if reviewErr != nil {
798						// FEAT-022 §12+§14: classify the failure into the four-class
799						// taxonomy and count prior review-error events scoped to the
800						// current result_rev. On the Nth failure emit a terminal
801						// review-manual-required event instead of yet another
802						// review-error, parking the bead so a subsequent loop
803						// iteration does NOT re-execute primary.
804						class := classifyReviewError(reviewErr, reviewRes)
805						prior := countPriorReviewErrors(w.Store, candidate.ID, report.ResultRev)
806						attemptCount := prior + 1
807						maxRetries := rcfg.ReviewMaxRetries()
808						if maxRetries <= 0 {
809							maxRetries = DefaultReviewMaxRetries
810						}
811						errSummary := EventBodySummary{
812							InputBytes:  0,
813							OutputBytes: 0,
814						}
815						if reviewRes != nil {
816							errSummary = EventBodySummary{
817								Harness:     reviewRes.ReviewerHarness,
818								Model:       reviewRes.ReviewerModel,
819								InputBytes:  reviewRes.InputBytes,
820								OutputBytes: reviewRes.OutputBytes,
821								ElapsedMS:   reviewRes.DurationMS,
822							}
823						}
824						if attemptCount >= maxRetries {
825							body := appendEventSummary(reviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error()), errSummary)
826							_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
827								Kind:      "review-manual-required",
828								Summary:   class,
829								Body:      body,
830								Actor:     assignee,
831								Source:    "ddx agent execute-loop",
832								CreatedAt: now().UTC(),
833							})
834							// Park the bead with a long cooldown so subsequent
835							// loop iterations do NOT re-pick it for primary
836							// re-execution. Reviewer-failure invariant (§13) is
837							// preserved: the bead is NOT closed.
838							parkUntil := now().UTC().Add(capLoopCooldown(MaxLoopCooldown))
839							_ = w.Store.SetExecutionCooldown(candidate.ID, parkUntil, "review-manual-required", class)
840						} else {
841							body := appendEventSummary(reviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error()), errSummary)
842							_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
843								Kind:      "review-error",
844								Summary:   class,
845								Body:      body,
846								Actor:     assignee,
847								Source:    "ddx agent execute-loop",
848								CreatedAt: now().UTC(),
849							})
850						}
851					} else {
852						report.ReviewVerdict = string(reviewRes.Verdict)
853						report.ReviewRationale = reviewRes.Rationale
854						// Persist the full reviewer stream as an artifact so the
855						// event body never carries the raw stream (ddx-f8a11202).
856						// On error the artifact path is empty and the event body
857						// still contains the short verdict summary; callers of this
858						// loop can recover the full text from the reviewer session
859						// log if the artifact write failed.
860						artifactPath, artifactErr := persistReviewerStream(runtime.ProjectRoot, candidate.ID, report.AttemptID, reviewRes.RawOutput)
861						if artifactErr != nil && runtime.Log != nil {
862							_, _ = fmt.Fprintf(runtime.Log, "reviewer stream artifact: %v\n", artifactErr)
863						}
864	
865						reviewSummary := EventBodySummary{
866							Harness:     reviewRes.ReviewerHarness,
867							Model:       reviewRes.ReviewerModel,
868							InputBytes:  reviewRes.InputBytes,
869							OutputBytes: reviewRes.OutputBytes,
870							ElapsedMS:   reviewRes.DurationMS,
871						}
872						switch reviewRes.Verdict {
873						case VerdictApprove:
874							// Approved: record the verdict event and then close.
875							// Closure must land AFTER the review event so the
876							// gate (ddx-e30e60a9) sees the terminal verdict.
877							_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
878								Kind:      "review",
879								Summary:   "APPROVE",
880								Body:      appendEventSummary(reviewEventBody("APPROVE", reviewRes.Rationale, artifactPath), reviewSummary),
881								Actor:     assignee,
882								Source:    "ddx agent execute-loop",
883								CreatedAt: now().UTC(),
884							})
885							if cerr := w.Store.CloseWithEvidence(candidate.ID, report.SessionID, report.ResultRev); cerr != nil {
886								if w.handleOutcomeStoreError(ctx, candidate.ID, "CloseWithEvidence", cerr, assignee, result, runtime, now) {
887									continue
888								}
889								return result, ctx.Err()
890							}
891						case VerdictRequestChanges:
892							// Needs fixes: record the review verdict, then reopen
893							// with findings in notes. The review event must land
894							// even on non-approve paths so review-outcomes can
895							// attribute the rejection to the originating tier.
896							_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
897								Kind:      "review",
898								Summary:   "REQUEST_CHANGES",
899								Body:      appendEventSummary(reviewEventBody("REQUEST_CHANGES", reviewRes.Rationale, artifactPath), reviewSummary),
900								Actor:     assignee,
901								Source:    "ddx agent execute-loop",
902								CreatedAt: now().UTC(),
903							})
904							reopenNotes := reviewRes.Rationale
905							if reopenNotes == "" {
906								reopenNotes = reviewRes.RawOutput
907							}
