1288	// emitPickerPrioritySkips fires a picker.priority_skip event when the picker
1289	// chose `chosen` while at least one strictly higher-priority bead was passed
1290	// over (ddx-9d55601f AC #4). Skips at the same priority as `chosen` are NOT
1291	// reported — those are FIFO order or label-filter siblings, not starvation.
1292	//
1293	// The emit is guarded so it costs nothing when the chosen bead is the highest-
1294	// priority bead the picker saw (the common case).
1295	func emitPickerPrioritySkips(emit func(string, map[string]any), chosen bead.Bead, skips []pickerSkip) {
1296		if len(skips) == 0 {
1297			return
1298		}
1299		var higher []map[string]any
1300		for _, s := range skips {
1301			if s.Priority < chosen.Priority {
1302				higher = append(higher, map[string]any{
1303					"bead_id":  s.BeadID,
1304					"priority": s.Priority,
1305					"reason":   s.Reason,
1306				})
1307			}
1308		}
1309		if len(higher) == 0 {
1310			return
1311		}
1312		emit("picker.priority_skip", map[string]any{
1313			"chosen_bead_id":  chosen.ID,
1314			"chosen_priority": chosen.Priority,
1315			"skipped":         higher,
1316		})
1317	}
