1319	// pickerSkip records a single bead that the picker passed over while looking
1320	// for the next candidate. It is used to emit a structured picker.priority_skip
1321	// event when a worker claims a lower-priority bead while a higher-priority
1322	// bead was skipped, so future starvation regressions are observable.
1323	//
1324	// Reason values are bounded to the set named in ddx-9d55601f AC #4:
1325	//
1326	//	label_filter, in_attempted, claim_race, eligibility_filter, retry_cooldown
1327	//
1328	// Note: eligibility_filter and retry_cooldown are applied upstream in
1329	// Store.ReadyExecution (so beads filtered for those reasons never reach
1330	// nextCandidate at all). They are part of the reason vocabulary so future
1331	// picker rearrangements can re-emit them without changing the schema.
1332	type pickerSkip struct {
1333		BeadID   string
1334		Priority int
1335		Reason   string
1336	}
1337	
1338	// nextCandidate returns the next claimable bead from the execution-ready
1339	// queue along with the list of higher-priority beads it skipped (and the
1340	// reason for each skip). The returned skips slice is only meaningful when
1341	// ok=true: it contains every entry that came BEFORE the chosen candidate
1342	// in the priority-sorted ReadyExecution result.
1343	func (w *ExecuteBeadWorker) nextCandidate(attempted map[string]struct{}, labelFilter string) (bead.Bead, []pickerSkip, bool, error) {
1344		ready, err := w.Store.ReadyExecution()
1345		if err != nil {
1346			return bead.Bead{}, nil, false, err
1347		}
1348		var skips []pickerSkip
1349		for _, candidate := range ready {
1350			if _, seen := attempted[candidate.ID]; seen {
1351				skips = append(skips, pickerSkip{BeadID: candidate.ID, Priority: candidate.Priority, Reason: "in_attempted"})
1352				continue
1353			}
1354			if labelFilter != "" && !HasBeadLabel(candidate.Labels, labelFilter) {
1355				skips = append(skips, pickerSkip{BeadID: candidate.ID, Priority: candidate.Priority, Reason: "label_filter"})
1356				continue
1357			}
1358			return candidate, skips, true, nil
1359		}
1360		return bead.Bead{}, skips, false, nil
1361	}
